&lt;%
const letters = [...new Set(items.map(item =&gt; item.title[0].toUpperCase()))].sort();
%&gt;


&lt;% for (const letter of letters) { %&gt;
  &lt;%= letter %&gt;

  &lt;% const letterItems = items.filter(item =&gt; item.title[0].toUpperCase() === letter); %&gt;
  &lt;% for (const item of letterItems) { %&gt;
    &lt;%= item.title %&gt;
    &lt;%= item.description %&gt;
  &lt;% } %&gt;

&lt;% } %&gt;



